// generar_221_fechaselector_en_todas_partes.js
// CHIQUI Entre Señales — FechaSelector en TODOS los campos de fecha
//
// Al registrar una mascota, la fecha de nacimiento abría el calendario
// nativo del navegador (Google) en vez de nuestro FechaSelector --
// violación de la regla #7 del proyecto. La barrida encontró TRES
// inputs de fecha nativos que se corrigen aquí:
//
// 1) app/mascota/nueva/page.tsx → fecha de nacimiento (el que viste).
// 2) app/registro-diario/page.tsx → "próxima fecha" del mini-modal de
//    vacuna/antiparasitario/medicamento.
// 3) app/perfil/page.tsx → fecha de nacimiento al editar el perfil.
//
// (El de PesoTracker ya se corrigió en el generar_218.)
// Los tres archivos conservan todos los cambios anteriores (216, 220).
// No hay SQL.
//
// Uso: arrastrar este archivo a la raíz del proyecto y correr:
//   node generar_221_fechaselector_en_todas_partes.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "app/mascota/nueva/page.tsx",
    base64: ""
  },
  {
    ruta: "app/registro-diario/page.tsx",
    base64: ""
  },
  {
    ruta: "app/perfil/page.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('')
  console.log('Listo. 3 archivos escritos correctamente.')
  console.log('Revisa git status (los 3 deben salir como modified) y luego git add / commit / push.')
} else {
  console.error('')
  console.error('Terminó con ' + errores + ' error(es). NO hagas git push todavía.')
  process.exit(1)
}
